 if ((i % 2) == 0) {
 mem_free(vptr[i]);
 }
 }

 dump_mem();
 dump_bins();
 mem_check(true);

 for (int i = 0; i < ITEMS_NUMBER; ++i) {
 if ((i % 2) != 0) {
 mem_free(vptr[i]);
 }
 }

 dump_mem();
 dump_bins();
 mem_check(true);
 return 0;
}
